mapper.select:
SELECT user_id
FROM
md_user_org rg
JOIN md_user us ON (rg.user_id = us.id)
WHERE rg.org_id = #{orgId}
AND us.phone = #{phone}

SELECT user_id
FROM
md_user_org rg
JOIN md_user us ON (rg.user_id = us.id)
WHERE rg.org_id != #{orgId}
AND us.phone = #{phone}
AND us.nickname != #{name}
GROUP BY user_id

SELECT user_id
FROM md_user_org rg
RIGHT JOIN md_user us ON (rg.user_id = us.id)
WHERE rg.org_id != #{orgId}
AND us.phone = #{phone}
AND us.email != #{email}
GROUP BY user_id

SELECT muo.org_id as orgId, mo.name as orgName,ex.custom_id customId
FROM md_user_org muo
LEFT JOIN md_org mo ON muo.org_id = mo.id
LEFT JOIN `md_org_external` ex ON muo.org_id=ex.org_id
WHERE muo.user_id = #{userId}
AND muo.tenant_id = #{tenantId}

SELECT user_id
FROM md_user_org rg
WHERE rg.org_id = #{orgId}
AND rg.tenant_id = #{tenantId}

SELECT org_id
FROM md_user_org rg
WHERE rg.user_id = #{userId}
AND rg.tenant_id = #{tenantId}

SELECT COUNT(1)
FROM md_app_tenant mat
LEFT JOIN md_user_org muo ON mat.tenant_id = muo.tenant_id
AND mat.app_id = #{appKey}
WHERE muo.user_id = #{userId}

